class GameState(Enum):
    WAITING = "waiting"
    IN_PROGRESS = "in_progress"
    PAUSED = "paused"
    FINISHED = "finished"


@dataclass
class Player:
    player_id: int
    name: str
    score: int
    ping: int
    team: str
    kills: int
    deaths: int
    assists: int
    connected_time: float
    ip_address: str
    is_alive: bool = True
    current_weapon: str = "rifle"


@dataclass
class ServerInfo:
    server_name: str
    map_name: str
    game_mode: str
    game_state: str
    max_players: int
    current_players: int
    tick_rate: int
    uptime: float
    version: str
    password_protected: bool
    vac_enabled: bool
    rules: Dict[str, str] = field(default_factory=dict)


# Protocol constants
QUERY_HEADER = b'\xFF\xFF\xFF\xFF'
QUERY_INFO = b'T'
QUERY_PLAYERS = b'U'
QUERY_RULES = b'R'
QUERY_CHALLENGE = b'W'
QUERY_FULL_STATUS = b'S'  # Custom: full status dump
QUERY_PING = b'P'

RESPONSE_INFO = b'I'
RESPONSE_PLAYERS = b'D'
RESPONSE_RULES = b'E'
RESPONSE_CHALLENGE = b'A'
RESPONSE_FULL_STATUS = b'F'
RESPONSE_PONG = b'Q'
RESPONSE_FRAGMENT = b'X'  # For fragmented large responses

# Fragment settings
MAX_FRAGMENT_SIZE = 1200  # Safe UDP payload size


class FragmentAssembler:
    """Handles fragmenting large responses for UDP transmission."""

    @staticmethod
    def fragment_data(data: bytes, request_id: int) -> List[bytes]:
        """Split large data into UDP-safe fragments."""
        fragments = []
        total_fragments = (len(data) + MAX_FRAGMENT_SIZE - 1) // MAX_FRAGMENT_SIZE

        for i in range(total_fragments):
            start = i * MAX_FRAGMENT_SIZE
            end = min(start + MAX_FRAGMENT_SIZE, len(data))
            chunk = data[start:end]

            # Fragment header: HEADER + RESPONSE_FRAGMENT + request_id(4) + fragment_num(2) + total_fragments(2) + chunk_size(2)
            header = QUERY_HEADER + RESPONSE_FRAGMENT
            header += struct.pack('<IHH H', request_id, i, total_fragments, len(chunk))
            fragments.append(header + chunk)

        return fragments


class GameWorld:
    """Simulates a game world with players and state."""

    def __init__(self, server_name: str, max_players: int = 64):
        self.server_name = server_name
        self.max_players = max_players
        self.map_name = "de_dust2"
        self.game_mode = "competitive"
        self.game_state = GameState.WAITING
        self.tick_rate = 128
        self.start_time = time.time()
        self.version = "1.0.42"
        self.password_protected = False
        self.vac_enabled = True
        self.players: Dict[int, Player] = {}
        self.next_player_id = 1
        self.rules = {
            "mp_timelimit": "30",
            "mp_roundtime": "1.75",
            "mp_freezetime": "15",
            "mp_buytime": "20",
            "mp_maxrounds": "30",
            "sv_gravity": "800",
            "sv_friction": "4",
            "mp_friendlyfire": "1",
            "mp_autoteambalance": "1",
            "sv_alltalk": "0",
            "mp_startmoney": "800",
            "mp_c4timer": "40",
        }
        self.lock = threading.Lock()

    def add_player(self, name: str, ip_address: str = "0.0.0.0") -> Player:
        with self.lock:
            teams = ["CT", "T"]
            weapons = ["rifle", "smg", "shotgun", "sniper", "pistol", "knife"]
            player = Player(
                player_id=self.next_player_id,
                name=name,
                score=random.randint(0, 50),
                ping=random.randint(5, 200),
                team=random.choice(teams),
                kills=random.randint(0, 30),
                deaths=random.randint(0, 25),
                assists=random.randint(0, 15),
                connected_time=time.time(),
                ip_address=ip_address,
                is_alive=random.choice([True, True, True, False]),
                current_weapon=random.choice(weapons),
            )
            self.players[self.next_player_id] = player
            self.next_player_id += 1

            if len(self.players) >= 2 and self.game_state == GameState.WAITING:
                self.game_state = GameState.IN_PROGRESS

            return player

    def remove_player(self, player_id: int) -> bool:
        with self.lock:
            if player_id in self.players:
                del self.players[player_id]
                if len(self.players) < 2:
                    self.game_state = GameState.WAITING
                return True
            return False

    def get_server_info(self) -> ServerInfo:
        with self.lock:
            return ServerInfo(
                server_name=self.server_name,
                map_name=self.map_name,
                game_mode=self.game_mode,
                game_state=self.game_state.value,
                max_players=self.max_players,
                current_players=len(self.players),
                tick_rate=self.tick_rate,
                uptime=time.time() - self.start_time,
                version=self.version,
                password_protected=self.password_protected,
                vac_enabled=self.vac_enabled,
                rules=dict(self.rules),
            )

    def get_players_list(self) -> List[Player]:
        with self.lock:
            return list(self.players.values())

    def get_full_status(self) -> dict:
        """Return complete server status including all players and game state."""
        with self.lock:
            info = ServerInfo(
                server_name=self.server_name,
                map_name=self.map_name,
                game_mode=self.game_mode,
                game_state=self.game_state.value,
                max_players=self.max_players,
                current_players=len(self.players),
                tick_rate=self.tick_rate,
                uptime=time.time() - self.start_time,
                version=self.version,
                password_protected=self.password_protected,
                vac_enabled=self.vac_enabled,
                rules=dict(self.rules),
            )

            players_data = []
            for p in self.players.values():
                pd = asdict(p)
                pd['connected_duration'] = time.time() - p.connected_time
                players_data.append(pd)

            teams_summary = {}
            for p in self.players.values():
                if p.team not in teams_summary:
                    teams_summary[p.team] = {
                        "player_count": 0,
                        "total_kills": 0,
                        "total_deaths": 0,
                        "total_score": 0,
                        "alive_count": 0,
                    }
                ts = teams_summary[p.team]
                ts["player_count"] += 1
                ts["total_kills"] += p.kills
                ts["total_deaths"] += p.deaths
                ts["total_score"] += p.score
                if p.is_alive:
                    ts["alive_count"] += 1

            return {
                "server_info": asdict(info),
                "players": players_data,
                "teams": teams_summary,
                "timestamp": time.time(),
                "query_protocol_version": 2,
            }

    def simulate_tick(self):
        """Simulate game activity."""
        with self.lock:
            for player in self.players.values():
                # Simulate ping fluctuation
                player.ping = max(5, player.ping + random.randint(-10, 10))
                # Occasionally update scores
                if random.random() < 0.05:
                    player.kills += 1
                    player.score += 2
                if random.random() < 0.04:
                    player.deaths += 1
                if random.random() < 0.03:
                    player.assists += 1
                if random.random() < 0.02:
                    player.is_alive = not player.is_alive


class ChallengeManager:
    """Manages challenge-response tokens to prevent spoofing for certain queries."""

    def __init__(self, expiry_seconds: float = 30.0):
        self.challenges: Dict[str, tuple] = {}  # addr_str -> (token, timestamp)
        self.expiry = expiry_seconds
        self.lock = threading.Lock()

    def generate_challenge(self, addr: tuple) -> int:
        token = random.randint(1, 0xFFFFFFFF)
        addr_str = f"{addr[0]}:{addr[1]}"
        with self.lock:
            self.challenges[addr_str] = (token, time.time())
        return token

    def validate_challenge(self, addr: tuple, token: int) -> bool:
        addr_str = f"{addr[0]}:{addr[1]}"
        with self.lock:
            if addr_str in self.challenges:
                stored_token, timestamp = self.challenges[addr_str]
                if time.time() - timestamp < self.expiry and stored_token == token:
                    del self.challenges[addr_str]
                    return True
                elif time.time() - timestamp >= self.expiry:
                    del self.challenges[addr_str]
        return False

    def cleanup(self):
        with self.lock:
            now = time.time()
            expired = [k for k, (_, ts) in self.challenges.items() if now - ts >= self.expiry]
            for k in expired:
                del self.challenges[k]


class RateLimiter:
    """Simple rate limiter per IP address."""

    def __init__(self, max_requests: int = 30, window_seconds: float = 10.0):
        self.max_requests = max_requests
        self.window = window_seconds
        self.requests: Dict[str, List[float]] = {}
        self.lock = threading.Lock()

    def is_allowed(self, ip: str) -> bool:
        now = time.time()
        with self.lock:
            if ip not in self.requests:
                self.requests[ip] = [now]
                return True

            # Remove old entries
            self.requests[ip] = [t for t in self.requests[ip] if now - t < self.window]
            if len(self.requests[ip]) < self.max_requests:
                self.requests[ip].append(now)
                return True

            return False

    def cleanup(self):
        now = time.time()
        with self.lock:
            empty_keys = []
            for ip, timestamps in self.requests.items():
                self.requests[ip] = [t for t in timestamps if now - t < self.window]
                if not self.requests[ip]:
                    empty_keys.append(ip)
            for k in empty_keys:
                del self.requests[k]


class GameServer:
    """Main game server handling UDP queries."""

    def __init__(self, host: str = "0.0.0.0", port: int = 27015, server_name: str = "My Game Server"):
        self.host = host
        self.port = port
        self.sock: Optional[socket.socket] = None
        self.running = False
        self.game_world = GameWorld(server_name=server_name)
        self.challenge_manager = ChallengeManager()
        self.rate_limiter = RateLimiter()
        self.fragmenter = FragmentAssembler()
        self.request_counter = 0
        self.request_counter_lock = threading.Lock()
        self.stats = {
            "total_queries": 0,
            "info_queries": 0,
            "player_queries": 0,
            "rules_queries": 0,
            "full_status_queries": 0,
            "ping_queries": 0,
            "rate_limited": 0,
            "invalid_queries": 0,
            "fragments_sent": 0,
        }
        self.stats_lock = threading.Lock()

    def _next_request_id(self) -> int:
        with self.request_counter_lock:
            self.request_counter += 1
            return self.request_counter

    def _increment_stat(self, key: str):
        with self.stats_lock:
            self.stats[key] = self.stats.get(key, 0) + 1

    def _encode_string(self, s: str) -> bytes:
        """Encode a string as null-terminated UTF-8."""
        return s.encode('utf-8') + b'\x00'

    def _build_info_response(self) -> bytes:
        """Build binary info response."""
        info = self.game_world.get_server_info()
        response = QUERY_HEADER + RESPONSE_INFO
        response += struct.pack('<B', 49)  # Protocol version
        response += self._encode_string(info.server_name)
        response += self._encode_string(info.map_name)
        response += self._encode_string(info.game_mode)
        response += self._encode_string(info.game_state)
        response += struct.pack('<H', info.current_players)
        response += struct.pack('<H', info.max_players)
        response += struct.pack('<H', info.tick_rate)
        response += struct.pack('<B', 1 if info.password_protected else 0)
        response += struct.pack('<B', 1 if info.vac_enabled else 0)
        response += self._encode_string(info.version)
        response += struct.pack('<f', info.uptime)
        return response

    def _build_players_response(self) -> bytes:
        """Build binary players response."""
        players = self.game_world.get_players_list()
        response = QUERY_HEADER + RESPONSE_PLAYERS
        response += struct.pack('<H', len(players))

        for i, player in enumerate(players):
            response += struct.pack('<B', i)
            response += self._encode_string(player.name)
            response += struct.pack('<i', player.score)
            response += struct.pack('<f', time.time() - player.connected_time)
            response += struct.pack('<H', player.ping)
            response += self._encode_string(player.team)
            response += struct.pack('<i', player.kills)
            response += struct.pack('<i', player.deaths)
            response += struct.pack('<i', player.assists)
            response += struct.pack('<B', 1 if player.is_alive else 0)
            response += self._encode_string(player.current_weapon)

        return response

    def _build_rules_response(self) -> bytes:
        """Build binary rules response."""
        info = self.game_world.get_server_info()
        rules = info.rules
        response = QUERY_HEADER + RESPONSE_RULES
        response += struct.pack('<H', len(rules))

        for key, value in rules.items():
            response += self._encode_string(key)
            response += self._encode_string(value)

        return response

    def _build_full_status_response(self) -> bytes:
        """Build JSON full status response (potentially large)."""
        status = self.game_world.get_full_status()
        json_data = json.dumps(status, indent=2, default=str).encode('utf-8')

        # This response uses JSON and can be large, requiring fragmentation
        response = QUERY_HEADER + RESPONSE_FULL_STATUS
        response += struct.pack('<I', len(json_data))
        response += json_data
        return response

    def _build_challenge_response(self, token: int) -> bytes:
        """Build challenge response."""
        return QUERY_HEADER + RESPONSE_CHALLENGE + struct.pack('<I', token)

    def _build_pong_response(self) -> bytes:
        """Build pong response."""
        return QUERY_HEADER + RESPONSE_PONG + struct.pack('<d', time.time())

    def _send_response(self, data: bytes, addr: tuple):
        """Send response, fragmenting if necessary."""
        if len(data) <= MAX_FRAGMENT_SIZE + 50:  # Small enough for single packet
            self.sock.sendto(data, addr)
        else:
            # Fragment the response
            request_id = self._next_request_id()
            fragments = self.fragmenter.fragment_data(data, request_id)
            for fragment in fragments:
                self.sock.sendto(fragment, addr)
                self._increment_stat("fragments_sent")
                # Small delay between fragments to avoid overwhelming the receiver
                time.sleep(0.001)

    def _handle_query(self, data: bytes, addr: tuple):
        """Process an incoming query."""
        ip = addr[0]

        # Rate limiting
        if not self.rate_limiter.is_allowed(ip):
            self._increment_stat("rate_limited")
            return

        self._increment_stat("total_queries")

        # Validate minimum packet size
        if len(data) < 5:
            self._increment_stat("invalid_queries")
            return

        # Check header
        if data[:4] != QUERY_HEADER:
            self._increment_stat("invalid_queries")
            return

        query_type = data[4:5]

        try:
            if query_type == QUERY_PING:
                self._increment_stat("ping_queries")
                response = self._build_pong_response()
                self.sock.sendto(response, addr)

            elif query_type == QUERY_INFO:
                self._increment_stat("info_queries")
                response = self._build_info_response()
                self._send_response(response, addr)

            elif query_type == QUERY_PLAYERS:
                self._increment_stat("player_queries")
                # Players query requires challenge-response
                if len(data) >= 9:
                    token = struct.unpack('<I', data[5:9])[0]
                    if token == 0xFFFFFFFF:
                        # Client is requesting a challenge
                        challenge_token = self.challenge_manager.generate_challenge(addr)
                        response = self._build_challenge_response(challenge_token)
                        self.sock.sendto(response, addr)
                    elif self.challenge_manager.validate_challenge(addr, token):
                        response = self._build_players_response()
                        self._send_response(response, addr)
                    else:
                        # Invalid challenge, send new one
                        challenge_token = self.challenge_manager.generate_challenge(addr)
                        response = self._build_challenge_response(challenge_token)
                        self.sock.sendto(response, addr)
                else:
                    # No challenge token provided, send challenge
                    challenge_token = self.challenge_manager.generate_challenge(addr)
                    response = self._build_challenge_response(challenge_token)
                    self.sock.sendto(response, addr)

            elif query_type == QUERY_RULES:
                self._increment_stat("rules_queries")
                # Rules query requires challenge-response
                if len(data) >= 9:
                    token = struct.unpack('<I', data[5:9])[0]
                    if token == 0xFFFFFFFF:
                        challenge_token = self.challenge_manager.generate_challenge(addr)
                        response = self._build_challenge_response(challenge_token)
                        self.sock.sendto(response, addr)
                    elif self.challenge_manager.validate_challenge(addr, token):
                        response = self._build_rules_response()
                        self._send_response(response, addr)
                    else:
                        challenge_token = self.challenge_manager.generate_challenge(addr)
                        response = self._build_challenge_response(challenge_token)
                        self.sock.sendto(response, addr)
                else:
                    challenge_token = self.challenge_manager.generate_challenge(addr)
                    response = self._build_challenge_response(challenge_token)
                    self.sock.sendto(response, addr)

            elif query_type == QUERY_FULL_STATUS:
                self._increment_stat("full_status_queries")
                # Full status - open to any IP for server browser
                response = self._build_full_status_response()
                self._send_response(response, addr)

            elif query_type == QUERY_CHALLENGE:
                # Generic challenge request
                challenge_token = self.challenge_manager.generate_challenge(addr)
                response = self._build_challenge_response(challenge_token)
                self.sock.sendto(response, addr)

            else:
                self._increment_stat("invalid_queries")

        except Exception as e:
            print(f"[ERROR] Error handling query from {addr}: {e}")
            import traceback
            traceback.print_exc()

    def _simulation_loop(self):
        """Background thread to simulate game activity."""
        maps = ["de_dust2", "de_mirage", "de_inferno", "de_nuke", "de_overpass",
                "de_train", "de_cache", "de_vertigo", "de_ancient"]
        bot_names = [
            "FragMaster", "SniperElite", "RushB_NoStop", "HeadshotHero",
            "SilentAssassin", "BombPlanter", "FlashBangKing", "SmokeNinja",
            "AceHunter", "WallBanger", "OneTapMachine", "ClutchKing",
            "EcoWarrior", "AWPGod", "EntryFragger", "LurkMaster",
            "Rotator9000", "DefaultDave", "StackSite", "PopFlash",
            "MollyMaster", "NadeKing", "CrossfireSetup", "TradeKiller",
            "AntiEco", "ForcebuySam", "SaveRound", "TimingGod",
            "PeekAboo", "JigglePeeker", "WidePeekWilson", "ShoulderPeek",
        ]

        # Add some initial players
        for name in random.sample(bot_names, min(12, len(bot_names))):
            ip = f"192.168.{random.randint(1, 254)}.{random.randint(1, 254)}"
            self.game_world.add_player(name, ip)

        self.game_world.game_state = GameState.IN_PROGRESS

        tick = 0
        while self.running:
            time.sleep(1.0)
            tick += 1

            # Simulate game ticks
            self.game_world.simulate_tick()

            # Occasionally add/remove players
            if tick % 15 == 0 and random.random() < 0.3:
                players = self.game_world.get_players_list()
                if len(players) < self.game_world.max_players and bot_names:
                    available = [n for n in bot_names if n not in [p.name for p in players]]
                    if available:
                        name = random.choice(available)
                        ip = f"192.168.{random.randint(1, 254)}.{random.randint(1, 254)}"
                        self.game_world.add_player(name, ip)
                        print(f"[GAME] Player '{name}' connected")

            if tick % 20 == 0 and random.random() < 0.2:
                players = self.game_world.get_players_list()
                if len(players) > 4:
                    player = random.choice(players)
                    self.game_world.remove_player(player.player_id)
                    print(f"[GAME] Player '{player.name}' disconnected")

            # Occasionally change map
            if tick % 120 == 0 and random.random() < 0.3:
                with self.game_world.lock:
                    old_map = self.game_world.map_name
                    self.game_world.map_name = random.choice(maps)
                    if self.game_world.map_name != old_map:
                        print(f"[GAME] Map changed to {self.game_world.map_name}")
                        # Reset scores on map change
                        for p in self.game_world.players.values():
                            p.score = 0
                            p.kills = 0
                            p.deaths = 0
                            p.assists = 0
                            p.is_alive = True

            # Cleanup stale challenges and rate limiter entries
            if tick % 30 == 0:
                self.challenge_manager.cleanup()
                self.rate_limiter.cleanup()

            # Print stats periodically
            if tick % 60 == 0:
                with self.stats_lock:
                    stats_copy = dict(self.stats)
                players = self.game_world.get_players_list()
                print(f"[STATS] Players: {len(players)}, "
                      f"Queries: {stats_copy['total_queries']}, "
                      f"Rate limited: {stats_copy['rate_limited']}, "
                      f"Fragments sent: {stats_copy['fragments_sent']}")

    def start(self):
        """Start the game server."""
        self.sock = socket.socket(socket.AF_INET, socket.SOCK_DGRAM)
        self.sock.setsockopt(socket.SOL_SOCKET, socket.SO_REUSEADDR, 1)

        # Increase send/receive buffer sizes for large responses
        self.sock.setsockopt(socket.SOL_SOCKET, socket.SO_SNDBUF, 1024 * 1024)
        self.sock.setsockopt(socket.SOL_SOCKET, socket.SO_RCVBUF, 1024 * 1024)

        self.sock.bind((self.host, self.port))
        self.sock.settimeout(1.0)

        self.running = True

        print(f"[SERVER] Game server starting on {self.host}:{self.port}")
        print(f"[SERVER] Server name: {self.game_world.server_name}")
        print(f"[SERVER] Accepting status queries from any IP address")
        print(f"[SERVER] Max fragment size: {MAX_FRAGMENT_SIZE} bytes")
        print()

        # Start simulation thread
        sim_thread = threading.Thread(target=self._simulation_loop, daemon=True)
        sim_thread.start()

        # Main query handling loop
        print("[SERVER] Listening for queries...")
        try:
            while self.running:
                try:
                    data, addr = self.sock.recvfrom(4096)
                    # Handle each query in a thread to not block
                    handler_thread = threading.Thread(
                        target=self._handle_query,
                        args=(data, addr),
                        daemon=True
                    )
                    handler_thread.start()
                except socket.timeout:
                    continue
                except OSError:
                    if self.running:
                        raise
                    break
        except KeyboardInterrupt:
            print("\n[SERVER] Shutting down...")
        finally:
            self.stop()

    def stop(self):
        """Stop the game server."""
        self.running = False
        if self.sock:
            self.sock.close()
            self.sock = None
        print("[SERVER] Server stopped.")


class GameServerBrowserClient:
    """Client for querying game servers - for testing and as reference implementation."""

    def __init__(self, timeout: float = 5.0):
        self.sock = socket.socket(socket.AF_INET, socket.SOCK_DGRAM)
        self.sock.settimeout(timeout)
        self.sock.setsockopt(socket.SOL_SOCKET, socket.SO_RCVBUF, 1024 * 1024)
        self.fragment_buffers: Dict[int, Dict[int, bytes]] = {}
        self.fragment_totals: Dict[int, int] = {}

    def close(self):
        self.sock.close()

    def _receive_response(self, expected_count: int = 1) -> List[bytes]:
        """Receive one or more response packets, handling fragmentation."""
        responses = []
        fragments: Dict[int, Dict[int, bytes]] = {}
        fragment_totals: Dict[int, int] = {}

        max_attempts = expected_count * 20  # Allow for many fragments
        attempts = 0

        while attempts < max_attempts:
            try:
                data, addr = self.sock.recvfrom(65535)
                attempts += 1

                if len(data) < 5:
                    continue

                if data[:4] != QUERY_HEADER:
                    continue

                response_type = data[4:5]

                if response_type == RESPONSE_FRAGMENT:
                    # Parse fragment header
                    if len(data) < 15:
                        continue
                    request_id, frag_num, total_frags, chunk_size = struct.unpack('<IHH H', data[5:15])
                    chunk = data[15:15 + chunk_size]

                    if request_id not in fragments:
                        fragments[request_id] = {}
                        fragment_totals[request_id] = total_frags

                    fragments[request_id][frag_num] = chunk

                    # Check if all fragments received
                    if len(fragments[request_id]) == fragment_totals[request_id]:
                        # Reassemble
                        full_data = b''
                        for i in range(total_frags):
                            if i in fragments[request_id]:
                                full_data += fragments[request_id][i]
                            else:
                                print(f"[CLIENT] Missing fragment {i} of {total_frags}")
                                break
                        else:
                            responses.append(full_data)
                            if len(responses) >= expected_count:
                                break
                else:
                    responses.append(data)
                    if len(responses) >= expected_count:
                        break

            except socket.timeout:
                break

        return responses

    def ping(self, host: str, port: int) -> Optional[float]:
        """Ping the server and return round-trip time in ms."""
        query = QUERY_HEADER + QUERY_PING
        start = time.time()
        self.sock.sendto(query, (host, port))

        responses = self._receive_response(1)
        if responses:
            rtt = (time.time() - start) * 1000
            return rtt
        return None

    def query_info(self, host: str, port: int) -> Optional[dict]:
        """Query basic server info."""
        query = QUERY_HEADER + QUERY_INFO
        self.sock.sendto(query, (host, port))

        responses = self._receive_response(1)
        if not responses:
            return None

        data = responses[0]
        if len(data) < 6 or data[4:5] != RESPONSE_INFO:
            return None

        result = {}
        offset = 5
        result['protocol'] = data[offset]
        offset += 1

        # Parse null-terminated strings
        def read_string(d, off):
            end = d.index(0, off)
            return d[off:end].decode('utf-8', errors='replace'), end + 1

        result['server_name'], offset = read_string(data, offset)
        result['map_name'], offset = read_string(data, offset)
        result['game_mode'], offset = read_string(data, offset)
        result['game_state'], offset = read_string(data, offset)

        result['current_players'] = struct.unpack('<H', data[offset:offset+2])[0]
        offset += 2
        result['max_players'] = struct.unpack('<H', data[offset:offset+2])[0]
        offset += 2
        result['tick_rate'] = struct.unpack('<H', data[offset:offset+2])[0]
        offset += 2
        result['password_protected'] = bool(data[offset])
        offset += 1
        result['vac_enabled'] = bool(data[offset])
        offset += 1
        result['version'], offset = read_string(data, offset)
        result['uptime'] = struct.unpack('<f', data[offset:offset+4])[0]

        return result

    def query_players(self, host: str, port: int) -> Optional[list]:
        """Query player list (with challenge-response)."""
        # First, request challenge
        query = QUERY_HEADER + QUERY_PLAYERS + struct.pack('<I', 0xFFFFFFFF)
        self.sock.sendto(query, (host, port))

        responses = self._receive_response(1)
        if not responses:
            return None

        data = responses[0]
        if len(data) < 9 or data[4:5] != RESPONSE_CHALLENGE:
            return None

        challenge_token = struct.unpack('<I', data[5:9])[0]

        # Now query with challenge token
        query = QUERY_HEADER + QUERY_PLAYERS + struct.pack('<I', challenge_token)
        self.sock.sendto(query, (host, port))

        responses = self._receive_response(1)
        if not responses:
            return None

        data = responses[0]
        if len(data) < 7:
            return None

        # Handle if it's a reassembled fragment
        if data[:4] == QUERY_HEADER and data[4:5] == RESPONSE_PLAYERS:
            offset = 5
        else:
            # Might be raw reassembled data starting with header
            if data[4:5] == RESPONSE_PLAYERS:
                offset = 5
            else:
                return None

        num_players = struct.unpack('<H', data[offset:offset+2])[0]
        offset += 2

        def read_string(d, off):
            end = d.index(0, off)
            return d[off:end].decode('utf-8', errors='replace'), end + 1

        players = []
        for _ in range(num_players):
            player = {}
            player['index'] = data[offset]
            offset += 1
            player['name'], offset = read_string(data, offset)
            player['score'] = struct.unpack('<i', data[offset:offset+4])[0]
            offset += 4
            player['duration'] = struct.unpack('<f', data[offset:offset+4])[0]
            offset += 4
            player['ping'] = struct.unpack('<H', data[offset:offset+2])[0]
            offset += 2
            player['team'], offset = read_string(data, offset)
            player['kills'] = struct.unpack('<i', data[offset:offset+4])[0]
            offset += 4
            player['deaths'] = struct.unpack('<i', data[offset:offset+4])[0]
            offset += 4
            player['assists'] = struct.unpack('<i', data[offset:offset+4])[0]
            offset += 4
            player['is_alive'] = bool(data[offset])
            offset += 1
            player['current_weapon'], offset = read_string(data, offset)
            players.append(player)

        return players

    def query_full_status(self, host: str, port: int) -> Optional[dict]:
        """Query full server status (JSON response, may be fragmented)."""
        query = QUERY_HEADER + QUERY_FULL_STATUS
        self.sock.sendto(query, (host, port))

        responses = self._receive_response(1)
        if not responses:
            return None

        data = responses[0]

        # Find the JSON data
        if data[:4] == QUERY_HEADER and data[4:5] == RESPONSE_FULL_STATUS:
            json_length = struct.unpack('<I', data[5:9])[0]
            json_data = data[9:9 + json_length]
        else:
            return None

        try:
            return json.loads(json_data.decode('utf-8'))
        except (json.JSONDecodeError, UnicodeDecodeError) as e:
            print(f"[CLIENT] Failed to parse JSON response: {e}")
            return None

    def query_rules(self, host: str, port: int) -> Optional[dict]:
        """Query server rules (with challenge-response)."""
        # Request challenge
        query = QUERY_HEADER + QUERY_RULES + struct.pack('<I', 0xFFFFFFFF)
        self.sock.sendto(query, (host, port))

        responses = self._receive_response(1)
        if not responses:
            return None

        data = responses[0]
        if len(data) < 9 or data[4:5] != RESPONSE_CHALLENGE:
            return None

        challenge_token = struct.unpack('<I', data[5:9])[0]

        # Query with token
        query = QUERY_HEADER + QUERY_RULES + struct.pack('<I', challenge_token)
        self.sock.sendto(query, (host, port))

        responses = self._receive_response(1)
        if not responses:
            return None

        data = responses[0]
        if data[4:5] != RESPONSE_RULES:
            return None

        offset = 5
        num_rules = struct.unpack('<H', data[offset:offset+2])[0]
        offset += 2

        def read_string(d, off):
            end = d.index(0, off)
            return d[off:end].decode('utf-8', errors='replace'), end + 1

        rules = {}
        for _ in range(num_rules):
            key, offset = read_string(data, offset)
            value, offset = read_string(data, offset)
            rules[key] = value

        return rules


def run_test_client(host: str = "127.0.0.1", port: int = 27015):
    """Run a test client that queries the server."""
    print("=" * 60)
    print("GAME SERVER BROWSER CLIENT - TEST")
    print("=" * 60)
    print()

    client = GameServerBrowserClient(timeout=5.0)

    try:
        # Ping
        print("[TEST] Pinging server...")
        rtt = client.ping(host, port)
        if rtt is not None:
            print(f"  Response time: {rtt:.1f}ms")
        else:
            print("  No response!")
            return
        print()

        # Server Info
        print("[TEST] Querying server info...")
        info = client.query_info(host, port)
        if info:
            print(f"  Server: {info['server_name']}")
            print(f"  Map: {info['map_name']}")
            print(f"  Mode: {info['game_mode']}")
            print(f"  State: {info['game_state']}")
            print(f"  Players: {info['current_players']}/{info['max_players']}")
            print(f"  Tick Rate: {info['tick_rate']}")
            print(f"  Version: {info['version']}")
            print(f"  Password: {info['password_protected']}")
            print(f"  VAC: {info['vac_enabled']}")
            print(f"  Uptime: {info['uptime']:.0f}s")
        else:
            print("  No response!")
        print()

        # Players
        print("[TEST] Querying player list...")
        players = client.query_players(host, port)
        if players:
            print(f"  Total players: {len(players)}")
            print(f"  {'Name':<20} {'Score':>6} {'K':>4} {'D':>4} {'A':>4} {'Ping':>5} {'Team':>5} {'Alive':>6} {'Weapon':<10}")
            print(f"  {'-'*18}   {'-'*4}  {'-'*3} {'-'*3} {'-'*3}  {'-'*4}  {'-'*4}  {'-'*4}  {'-'*8}")
            for p in players:
                print(f"  {p['name']:<20} {p['score']:>6} {p['kills']:>4} {p['deaths']:>4} {p['assists']:>4} {p['ping']:>5} {p['team']:>5} {'Yes' if p['is_alive'] else 'No':>6} {p['current_weapon']:<10}")
        else:
            print("  No response!")
        print()

        # Rules
        print("[TEST] Querying server rules...")
        rules = client.query_rules(host, port)
        if rules:
            for key, value in sorted(rules.items()):
                print(f"  {key}: {value}")
        else:
            print("  No response!")
        print()

        # Full Status (JSON)
        print("[TEST] Querying full status (JSON)...")
        status = client.query_full_status(host, port)
        if status:
            print(f"  Server: {status['server_info']['server_name']}")
            print(f"  Players: {status['server_info']['current_players']}")
            print(f"  Teams:")
            for team, data in status.get('teams', {}).items():
                print(f"    {team}: {data['player_count']} players, "
                      f"{data['total_kills']} kills, "
                      f"{data['alive_count']} alive")
            print(f"  Response size: ~{len(json.dumps(status))} bytes")
            print()
            print("  Full JSON response:")
            print(json.dumps(status, indent=2, default=str)[:2000])
            if len(json.dumps(status)) > 2000:
                print("  ... (truncated)")
        else:
            print("  No response!")

    finally:
        client.close()


def main():
    parser = argparse.ArgumentParser(description="Game Server with UDP Query Protocol")
    subparsers = parser.add_subparsers(dest="command", help="Command to run")

    # Server command
    server_parser = subparsers.add_parser("server", help="Run the game server")
    server_parser.add_argument("--host", default="0.0.0.0", help="Bind address (default: 0.0.0.0)")
    server_parser.add_argument("--port", type=int, default=27015, help="Bind port (default: 27015)")
    server_parser.add_argument("--name", default="My Awesome Game Server", help="Server name")
    server_parser.add_argument("--max-players", type=int, default=64, help="Max players (default: 64)")

    # Client command
    client_parser = subparsers.add_parser("client", help="Run the test client")
    client_parser.add_argument("--host", default="127.0.0.1", help="Server address (default: 127.0.0.1)")
    client_parser.add_argument("--port", type=int, default=27015, help="Server port (default: 27015)")

    args = parser.parse_args()

    if args.command == "server":
        server = GameServer(
            host=args.host,
            port=args.port,
            server_name=args.name,
        )
        server.game_world.max_players = args.max_players
        server.start()
    elif args.command == "client":
        run_test_client(args.host, args.port)
    else:
        # Default: run server
        print("No command specified. Use 'server' or 'client'.")
        print("Starting server by default...")
        print()
        server = GameServer()
        server.start()


if __name__ == "__main__":
    main()